dashboard.definition:

{
    "dataSources": {
        "ds_total_streams": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup spotify_tracks.csv | stats sum(streams) as value | eval label=\"Total Streams\" | eval delta=\"+12.4%\" | eval sparkline=\"8420000,8680000,9120000,9340000,9580000,9870000,10240000,10580000,10920000,11340000,11780000,12420000\""
            },
            "name": "Total Streams"
        },
        "ds_active_listeners": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup spotify_listening.csv | stats sum(listeners) as value | eval label=\"Active Listeners\" | eval delta=\"+18.6%\" | eval sparkline=\"4210000,4340000,4560000,4670000,4790000,4935000,5120000,5290000,5460000,5670000,5890000,6210000\""
            },
            "name": "Active Listeners"
        },
        "ds_playlist_adds": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup spotify_tracks.csv | stats sum(playlist_adds) as value | eval label=\"Playlist Adds\" | eval delta=\"+8.7%\" | eval sparkline=\"2840000,2920000,3080000,3150000,3230000,3320000,3440000,3560000,3680000,3820000,3960000,4180000\""
            },
            "name": "Playlist Adds"
        },
        "ds_listening_heatmap": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup spotify_listening.csv"
            },
            "name": "Listening Heatmap"
        },
        "ds_genres": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup spotify_genres.csv | sort - share"
            },
            "name": "Genre Distribution"
        },
        "ds_audio_wave_overview": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup spotify_tracks.csv | stats sum(streams) as value | eval label=\"streams/min\" | eval status=\"NOW PLAYING\""
            },
            "name": "Audio Wave Overview"
        },
        "ds_top_track_kpi": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup spotify_tracks.csv | sort - streams | head 1 | eval label=\"#1 Track Streams\" | eval delta=\"+22.1%\" | rename streams as value"
            },
            "name": "Top Track KPI"
        },
        "ds_total_artists_kpi": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup spotify_artists.csv | stats dc(artist) as value | eval label=\"Active Artists\" | eval delta=\"+4.2%\""
            },
            "name": "Total Artists KPI"
        },
        "ds_tracks": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup spotify_tracks.csv | sort - streams"
            },
            "name": "Top Tracks"
        },
        "ds_artists": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup spotify_artists.csv | sort - monthly_listeners"
            },
            "name": "Artist Growth"
        },
        "ds_total_playlists_kpi": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup spotify_playlists.csv | stats count as value | eval label=\"Total Playlists\" | eval delta=\"+6.1%\""
            },
            "name": "Total Playlists KPI"
        },
        "ds_avg_skip_kpi": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup spotify_playlists.csv | stats avg(skip_rate) as value | eval value=round(value,1) | eval label=\"Avg Skip Rate\" | eval delta=\"-1.8%\""
            },
            "name": "Avg Skip Rate KPI"
        },
        "ds_playlists": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup spotify_playlists.csv | sort - followers"
            },
            "name": "Playlist Performance"
        },
        "ds_trends": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup spotify_trends.csv | sort metric period"
            },
            "name": "Metric Trends"
        },
        "ds_audio_wave_playlists": {
            "type": "ds.search",
            "options": {
                "query": "| inputlookup spotify_playlists.csv | stats sum(followers) as value | eval label=\"total followers\" | eval status=\"PLAYLISTS\""
            },
            "name": "Audio Wave Playlists"
        }
    },
    "visualizations": {
        "viz_canvas_bg": {
            "type": "splunk.rectangle",
            "options": {
                "fillColor": "#121212",
                "strokeColor": "transparent"
            }
        },
        "viz_banner_bg": {
            "type": "splunk.rectangle",
            "options": {
                "fillColor": "#1E1E1E",
                "strokeColor": "transparent"
            }
        },
        "viz_banner_accent": {
            "type": "splunk.rectangle",
            "options": {
                "fillColor": "#1DB954",
                "strokeColor": "transparent"
            }
        },
        "viz_banner_title": {
            "type": "splunk.markdown",
            "options": {
                "markdown": "**SPOTIFY** &nbsp; ANALYTICS",
                "fontColor": "#E1E1E1",
                "fontSize": "extraLarge",
                "fontFamily": "Splunk Platform Sans",
                "backgroundColor": "transparent"
            }
        },
        "viz_section_overview": {
            "type": "splunk.markdown",
            "options": {
                "markdown": "STREAMING OVERVIEW",
                "fontColor": "rgba(255,255,255,0.30)",
                "fontSize": "extraSmall",
                "fontFamily": "Splunk Platform Sans",
                "backgroundColor": "transparent"
            }
        },
        "viz_total_streams": {
