            "dataSources": {
                "primary": "ds_total_streams"
            },
            "options": {
                "backgroundColor": "transparent",
                "spotify_viz_pack.stream_kpi.valueField": "value",
                "spotify_viz_pack.stream_kpi.labelField": "label",
                "spotify_viz_pack.stream_kpi.deltaField": "delta",
                "spotify_viz_pack.stream_kpi.sparklineField": "sparkline",
                "spotify_viz_pack.stream_kpi.accentColor": "#1DB954"
            }
        },
        "viz_active_listeners": {
