    "inputs": {},
    "layout": {
        "globalInputs": [],
        "tabs": {
            "items": [
                {"layoutId": "tab_overview", "label": "Overview"},
                {"layoutId": "tab_tracks", "label": "Tracks & Artists"},
                {"layoutId": "tab_playlists", "label": "Playlists"}
            ],
            "options": {
                "barPosition": "top",
                "showTabBar": true
            }
        },
        "layoutDefinitions": {
            "tab_overview": {
                "type": "absolute",
                "options": {"width": 1920, "height": 1080, "display": "auto-scale"},
                "structure": [
                    {"item": "viz_canvas_bg", "type": "block", "position": {"x": 0, "y": 0, "w": 1920, "h": 1080}},
                    {"item": "viz_banner_bg", "type": "block", "position": {"x": 0, "y": 0, "w": 1920, "h": 64}},
