                    {"item": "viz_card_wave_overview", "type": "block", "position": {"x": 1512, "y": 116, "w": 384, "h": 200}},
                    {"item": "viz_audio_wave_overview", "type": "block", "position": {"x": 1520, "y": 124, "w": 368, "h": 184}},

                    {"item": "viz_section_heatmap", "type": "block", "position": {"x": 24, "y": 332, "w": 300, "h": 24}},
                    {"item": "viz_card_heatmap", "type": "block", "position": {"x": 24, "y": 364, "w": 1872, "h": 320}},
                    {"item": "viz_heatmap", "type": "block", "position": {"x": 32, "y": 372, "w": 1856, "h": 304}},

                    {"item": "viz_section_genres", "type": "block", "position": {"x": 24, "y": 700, "w": 300, "h": 24}},
                    {"item": "viz_card_genres", "type": "block", "position": {"x": 24, "y": 732, "w": 1872, "h": 330}},
                    {"item": "viz_genres", "type": "block", "position": {"x": 32, "y": 740, "w": 1856, "h": 314}}
                ]
            },
            "tab_tracks": {
                "type": "absolute",
                "options": {"width": 1920, "height": 1080, "display": "auto-scale"},
